export function getNasConfigs(target: string): NasConfig[] {
  const nas1 = buildConfig(
    process.env.NAS_EDGE1_NAME ?? "edgesynology1",
    process.env.NAS_EDGE1_API_URL,           // e.g. http://100.107.131.35:7734
    process.env.NAS_EDGE1_API_SECRET,        // Bearer token
    process.env.NAS_EDGE1_API_SIGNING_KEY,   // HMAC key for approval tokens
  );
  const nas2 = buildConfig(
    process.env.NAS_EDGE2_NAME ?? "edgesynology2",
    process.env.NAS_EDGE2_API_URL,
    process.env.NAS_EDGE2_API_SECRET,
    process.env.NAS_EDGE2_API_SIGNING_KEY,
  );
  if (target === "both") return [nas1, nas2].filter(Boolean);
  const match = [nas1, nas2].find((c) => c?.name === target);
  return match ? [match] : [];
}
```

**Preview call** (lines 150–159, `nas-client.ts`):
```typescript
export async function nasPreview(config: NasConfig, command: string): Promise<NasPreviewResult> {
  return requestJson<NasPreviewResult>(
    config,
    "/preview",
    { command },
    PREVIEW_TIMEOUT_MS,  // 8s
    "NAS preview",
  );
}
```

**Exec call** (lines 165–176):
```typescript
export async function nasExec(
  config: NasConfig,
  command: string,
  tier: number,
  approvalToken?: string,
  timeoutMs = MAX_EXEC_TIMEOUT_MS,  // 25s
): Promise<NasExecResult> {
  const clampedTimeout = Math.min(timeoutMs, MAX_EXEC_TIMEOUT_MS);
  const body: Record<string, unknown> = { command, tier, timeout_ms: clampedTimeout };
  if (approvalToken) body.approval_token = approvalToken;
  return requestJson<NasExecResult>(config, "/exec", body, clampedTimeout + 5_000, "NAS exec");
}
```

**HTTP transport** (lines 40–99, `nas-client.ts`):
- Uses Node's `http` + `https` modules (not a third-party client)
- Sets `Connection: close` to prevent keep-alive pool exhaustion
- Uses `AbortController` + `setTimeout` for timeouts (not `AbortSignal.timeout()`)
- Max response size: 512 KB
- Headers include `Authorization: Bearer ${config.apiSecret}`

**Example tool execution flow:**
1. User calls `invoke_tool({ name: "start_btrfs_scrub", target: "edgesynology1", args: { filter: "volume1" } })`
2. MCP finds the tool definition and calls `buildCommand({ filter: "volume1", target: "edgesynology1" })`
3. buildCommand returns shell script: `btrfs scrub start '/btrfs/volume1'`
4. MCP calls `nasPreview(edgesynology1_config, <command>)` → nas-api responds with `{ tier: 2, summary: "...", blocked: false }`
5. MCP returns preview to user: "This action requires approval. Command: `btrfs scrub start '/btrfs/volume1'`. Call again with confirmed: true"
6. User calls `invoke_tool({ name: "start_btrfs_scrub", target: "edgesynology1", args: { filter: "volume1", confirmed: true } })`
7. MCP calls `buildApprovalToken()` → base64url-encoded HMAC-signed token
8. MCP calls `nasExec(edgesynology1_config, <command>, 2, <token>)` → nas-api verifies token and executes
9. nas-api returns `{ stdout: "...", stderr: "", exit_code: 0 }`
10. MCP returns result to user

