#### **Path B: Next.js API Routes (Server-side)**
Used for operations that need **authentication checks, Supabase writes, or calls to the NAS API**.

**Example route:** `/worksp/monitor/app/apps/web/src/app/api/settings/route.ts` (lines 1–92)

```tsx
import { NextResponse } from "next/server";
import { createClient as createSupabaseServerClient } from "@/lib/supabase/server";

export const runtime = "nodejs";
export const dynamic = "force-dynamic";

export async function GET() {
  try {
    const supabase = await createSupabaseServerClient();
    const { data: { user } } = await supabase.auth.getUser();

    if (!user) return NextResponse.json({ error: "Authentication required." }, { status: 401 });

    const { data } = await supabase.from("ai_settings").select("key, value");

    const settings: Record<string, string> = {};
    for (const row of data ?? []) {
      settings[row.key] = row.value;
    }

    return NextResponse.json({ settings });
  } catch (error) {
    return NextResponse.json({ error: error.message }, { status: 500 });
  }
}

export async function POST(request: Request) {
  const supabase = await createSupabaseServerClient();
  const { data: { user } } = await supabase.auth.getUser();

  if (!user) return NextResponse.json({ error: "Unauthenticated." }, { status: 401 });

  const body = await request.json();
  const { key, value } = body;

  // Upsert to Supabase (write operation)
  const { error } = await supabase.from("ai_settings").upsert(
    { key, value: value.trim(), updated_at: new Date().toISOString() },
    { onConflict: "key" }
  );

  if (error) throw error;
  return NextResponse.json({ ok: true });
}
```

