```tsx
const channel = supabase
  .channel("smon-nas-units")
  .on(
    "postgres_changes",
    { event: "*", schema: "public", table: "nas_units" },
    (payload) => {
      if (payload.eventType === "UPDATE") {
        setUnits((prev) =>
          prev.map((u) =>
            u.id === (payload.new as NasUnit).id
              ? (payload.new as NasUnit)
              : u
          )
        );
      }
    }
  )
  .subscribe();

return () => {
  supabase.removeChannel(channel);
};
```

